# Extract objects using regex and replace them
def replace_card(content, card_name, new_card_content):
    # Find the object that starts with "name": "card_name"
    pattern = r'  {\s+"name": "' + card_name + r'",.*?  }'
    return re.sub(pattern, new_card_content, content, flags=re.DOTALL)

